export const nextGeneration = (liveCells: Cell[]): Cell[] =>
  liveCells.filter(([x, y]) => {
    const liveNeighbors = liveCells.filter(
      ([nx, ny]) =>
        Math.abs(nx - x) <= 1 &&
        Math.abs(ny - y) <= 1 &&
        !(nx === x && ny === y),
    ).length;
    return liveNeighbors === 3;
  });
